/**
 * Comprehensive Indian Calendar data engine for WhatsToday.
 * Inspired by Kalnirnay-style coverage: Hindu, Marathi, National & Global days.
 * Includes recurring yearly logic + manually editable festival entries.
 */

export type FestivalCategory = "hindu" | "marathi" | "national" | "other" | "vrat";
export type FestivalType = "major" | "minor" | "holiday" | "vrat" | "ekadashi" | "purnima" | "amavasya";
export type DotColor = "red" | "blue" | "green";

export interface CalendarDay {
  date: string;
  tithi: string;
  tithiMr: string;
  nakshatra: string;
  nakshtraMr: string;
  vaar: string;
  vaarMr: string;
  festival?: string;
  festivalMr?: string;
  festivalType?: FestivalType;
  category?: FestivalCategory;
  paksha: "Shukla" | "Krishna";
  pakshaMr: "शुक्ल" | "कृष्ण";
  isHoliday?: boolean;
  isVrat?: boolean;
  dotColors?: DotColor[];

  // Today card sections
  mainEvent?: string;
  mainEventMr?: string;
  mainEventDesc?: string;
  mainEventDescMr?: string;
  indianSignificance?: string[];
  indianSignificanceMr?: string[];
  vrat?: string;
  vratMr?: string;
  globalObservance?: string;
  globalObservanceMr?: string;
  historyFact?: string;
  historyFactMr?: string;
  didYouKnow?: string;
  didYouKnowMr?: string;
  quote: string;
  quoteMr: string;
}

